import api from './api';

// Get all attendance records
export const getAttendances = async (params = {}) => {
    const response = await api.get('/attendances', { params });
    return response.data;
};

// Get single attendance record
export const getAttendance = async (id) => {
    const response = await api.get(`/attendances/${id}`);
    return response.data;
};

// Mark attendance
export const markAttendance = async (data) => {
    const response = await api.post('/attendances', data);
    return response.data;
};

// Mark bulk attendance
export const markBulkAttendance = async (data) => {
    const response = await api.post('/attendances/bulk', data);
    return response.data;
};

// Update attendance
export const updateAttendance = async (id, data) => {
    const response = await api.put(`/attendances/${id}`, data);
    return response.data;
};

// Delete attendance
export const deleteAttendance = async (id) => {
    const response = await api.delete(`/attendances/${id}`);
    return response.data;
};

// Get attendance summary
export const getAttendanceSummary = async (params) => {
    const response = await api.get('/attendances-summary', { params });
    return response.data;
};

// Get today's attendance
export const getTodayAttendance = async (companyId = null) => {
    const params = companyId ? { company_id: companyId } : {};
    const response = await api.get('/attendances-today', { params });
    return response.data;
};

// Get companies for super admin
export const getAttendanceCompanies = async () => {
    const response = await api.get('/attendance-companies');
    return response.data;
};

export default {
    getAttendances,
    getAttendance,
    markAttendance,
    markBulkAttendance,
    updateAttendance,
    deleteAttendance,
    getAttendanceSummary,
    getTodayAttendance,
    getAttendanceCompanies,
};
